/**
 * @class BxImg
 * @classDesc BxImg 클래스 생성자
 * @example
 *
 * <bx-img
 *      id="image1"
 *      url="http://68.media.tumblr.com/83ffbae5b815b091037d13548fd5b37e/tumblr_orwck9lRKi1slhhf0o1_1280.jpg"
 *      errUrl="http://68.media.tumblr.com/f5fdcf32198a2abb56508701ee65e41b/tumblr_osnjnznDb21slhhf0o1_1280.jpg"
 *      shape="square"
 *      overlayStyle="full"
 *      size="medium"
 *      frameType="default"
 *      data-width="400"
 *      data-height="400"
 *      data-title="테스트 타이틀 입니다"
 *      captionAlign="center"
 *      caption="caption test1"
 *      desc="align >> center"
 *      btnText="button">
 * </bx-img>
 *
 * <script>
 *
 *  $(document).ready(function(){
 *
 *  // DOM 이 ready 된 시점에서 초기화 함수를 호출한다.
 *      $().BxImg().initialize();
 *
 *      var image = document.getElementById('image1');
 *
 *      // 이미지 변경
 *      image.url = "http://68.media.tumblr.com/a2aa66013283367f774b020c83ad3ace/tumblr_ol9e886Wm61slhhf0o1_1280.jpg";
 *
 *      // 이미지 설명 변경
 *      image.desc = "이미지 설명입니다";
 *
 *      // 이미지 캡션
 *      image.caption = "버튼입니다";
 *
 *      // 이미지 내부 정렬
 *      image.captionAlign = "left";
 *
 *      // 이미지 가로 사이즈 변경
 *      image['data-width'] = 100;
 *
 *      // 이미지 가로 사이즈 변경
 *      image['data-height'] = 100;
 *
 *      // 이미지 타이틀 변경
 *      image['data-title'] = '테스트 타이틀';
 *
 *      // 이미지 렌더링 callback 설정
 *      image.bxrender = function(){
 *          console.log('render complete');
 *      }
 *
 *      // 이미지 버튼 클릭 callback 설정
 *      image.bxbtnclick = function(event){
 *          console.log('button clicked', event);
 *      }
 *
 * });
 *
 * </script>
 */

/**
 * @property {function} [bx-render = function(){}] - 컴포넌트 render 시, 호출될 callback 함수
 * @callback bxrender
 *
 * @memberOf BxImg
 */

/**
 * @property {function} [bx-btnClick = function(){}] - 이미지 버튼 클릭 시, 호출될 callback 함수
 * @callback bxbtnClick
 *
 * @param {object} event - 버튼 클릭시 callback 값
 * @memberOf BxImg
 */

