const CONSOLE = BXUI.Console;
const UTIL = BXUI.Util;
const FILE = BXUI.File;

// 이미지 모양 타입
const SHAPE = {
    "square": 'square',
    "round": 'rounded',
    "circle": 'circle'
};

// 이미지 크기
const SIZE = {
    "small": {
        "class": 'size-s',
        "value": 150
    },
    "medium": {
        "class": 'size-m',
        "value": 300
    },
    "large": {
        "class": 'size-l',
        "value": 500
    }
};

// 캡션 및 버튼 정렬
const ALIGN = {
    'center': '',
    'left': 'a-left',
    'right': 'a-right'
};

// Overlay Style
const OVERLAY_STYLE = {
    "half": 'half-type',
    "full": ''
};

const FRAME_TYPE = {
    "default": 'default',
    "horizon": 'fluid-width',
    "vertical": 'fluid-height'
};

const ATTRNAMES = {
    "errurl": "errUrl",
    "overlaystyle": "overlayStyle",
    "enablespotlight": "enableSpotlight",
    "captionalign": "captionAlign",
    "btntext": "btnText",
    "frametype": "frameType",
    "bx-btnclick": "bx-btnClick"
};

const READONLY_PROPERTY = {
    "shape": 'shape',
    "errUrl": 'errUrl',
    "size": 'size',
    "frameType": 'frameType',
    "overlayStyle": 'overlayStyle',
    "enableSpotlight": 'enableSpotlight'
};

const CLASS_NAME = {
    "wrap": 'bx-img-wrap',
    "desc": 'img-desc',
    "btn": 'img-btn'
};

// default 설정
const OPTS = {
    /**
     * @property {object} bx-img
     * @property {string} bx-img.url='' - 이미지 경로
     * @property {string} [bx-img.errUrl=''] - <span class='important'>readonly</span> - 에러시 출력할 이미지 경로
     * @property {string} [bx-img.shape='square'] - <span class='important'>readonly</span> - 이미지 모양 (square, round, circle)
     * @property {string} [bx-img.desc=''] - 이미지 하단 설명하는 텍스트 문구
     * @property {string} [bx-img.size=''] - <span class='important'>readonly</span> - 이미지 사이즈 (small, medium, large)
     * @property {object} [bx-img.data-width=null] - 이미지 가로 사이즈
     * @property {object} [bx-img.data-height=null] - 이미지 세로 사이즈
     * @property {string} [bx-img.frameType='default'] - <span class='important'>readonly</span> - 이미지 채우기 방향 설정 (default, horizon, vertical)
     * @property {string} [bx-img.overlayStyle='full'] - <span class='important'>readonly</span> - 마우스 오버시 overlay 모양 (half, full)
     * @property {string} [bx-img.captionAlign='center'] - 마우스 오버시 캡션 텍스트와 버튼의 정렬 위치 (left, center, right) <span class='important'>overlayStyle이 half 일 때 만 적용</span>
     * @property {string} [bx-img.caption=''] - 마우스 오버시 캡션 텍스트 문구
     * @property {string} [bx-img.btnText=''] - 마우스 오버시 버튼의 문구
     * @property {function} [bx-img.bx-render=function(){}] - 이미지 렌더링 완료 시, 호출될 callback 함수
     * @property {function} [bx-img.bx-btnClick=function(){}] - 이미지 내부 버튼 클릭 시, 호출될 callback 함수
     * @property {function} [bx-img.bx-[eventName]=function(){}] - eventName(click, focus 등) 에 해당되는, 네이티브 이벤트를 바인딩시킨다.
     *
     * @alias Attributes
     * @memberOf BxImg
     */
    // 이미지 관련 옵션
    "url": '',                              // 이미지 경로 - (get, set)
    "errUrl": '',                           // 에러시 출력할 이미지 경로 - (readonly)
    "shape": SHAPE.square,                   // 이미지 모양 - (readonly) square, round, circle
    "desc": '',                             // 이미지 외부 텍스트 - (get, set) 이미지 하단 문구
    "size": '',                             // 이미지 크기 - (readonly) small, medium, large
    "frameType": FRAME_TYPE.default,                  // 이미지 영역 - (readonly) default, horizon, vertical

    // dim 관련 옵션
    "overlayStyle": OVERLAY_STYLE.full,                     // 마우스 오버시 dim 옵션 - (readonly) half, full, clear

    // Spotlight 관련 옵션
    // "enableSpotlight": false,                // 라이트박스 표시 유무 - (readonly) true, false,

    // 캡션 관련 옵션
    "captionAlign": ALIGN.center,             // 캡션 텍스트 정렬 - (get, set) left, center
    "caption": '',                      // 캡션 텍스트 (html 적용) - (get, set)

    // 버튼 관련 옵션
    "btnText": '',                    // 버튼 텍스트 - (readonly)

    "data-width": null,
    "data-height": null,
    "data-title": null,

    // callback 관련 옵션
    "bx-render": function(){},              // 렌더링 후 callback - (get, set)
    "bx-btnClick": function(){}             // 버튼 클릭 callback - (get, set)
};

