const DIM_STYLE = {
    color: 'black',
    enableBlur: true,
    enableIcon: true,
    iconType: 'think'
};

const HEX = 16777215;                           // ffffff 10진수값
const UPDATE_DURATION = 350;                    // 이미지 appear 대기시간
const ERROR_IMG = 'assets/images/no-img.png';   // 에러 이미지 경로

class BxImg {

    constructor(){

        this.opts = OPTS;
        // super();
    }

    /**
     * 초기화 함수
     *
     * @returns {object} 생성된 인스턴스
     *
     * @memberOf BxImg
     */
    initialize(){

        this.$img = this.$root.find('bx-img');

        this.elems = [];

        _.forEach(this.$img, (elem) => {

            const $customElem = $(elem);

            // 사용자 커스텀 엘리먼트를 파싱한다.
            const $component = _parseCustomElement.call(this, $customElem);

            $component.prop('bxrender').call($component.get(0));

            this.elems.push($component.get(0));
        });

        return this;
    }
}

/**
 *
 * Custom Element 를 구별하기위한 플래그
 *
 * `커스텀 엘리먼트`의 경우에는 반드시 아래 프로퍼티값을 정의해야한다.
 *
 * @private
 * @type {boolean}
 */
BxImg.isCustomElement = true;

