/**
 * 사용자 `custom` 태그를 `native` 태그로 대치시킨다.
 *
 * @param {object} [$customElem=$(document.documentElement)] - 사용자 custom 엘리먼트
 *
 * @returns {object} 생성한 $container 엘리먼트
 *
 * @private
 *
 * @memberOf BxImg
 */
function _parseCustomElement($customElem = $(document.documentElement)){

    if (!_.isElement($customElem.get(0))){
        CONSOLE.prop.throw(BxImg, '$customElem', 'type');
    }

    // $container 엘리먼트를 생성한다.
    const $container = BASE.appendContainerElement(BxImg.$root, BxImg.className);

    // 컴포넌트 엘리먼트를 생성한다.
    const $component = _getComponentElement.call(this, $customElem);

    // 컴포넌트 이벤트 리스너 등록
    _addDocumentElementEventListener.call(this, $component);

    // 반환받은 `컴포넌트 엘리먼트`를 `컨테이너 엘리먼트`의 자식으로 추가한다.
    $container.append($component);

    // $customElem 엘리먼트를 생성된 `$container` 엘리먼트로 대치시킨다.
    $customElem.replaceWith($container);

    // 이미지 업데이트
    _update($component);

    return $component;
}

/**
 * component 엘리먼트를 반환한다.
 *
 * @param {object} [$customElem=$(document.documentElement)] - 사용자 custom 엘리먼트
 *
 * @returns {object} 생성한 component 엘리먼트
 *
 * @private
 *
 * @memberOf BxImg
 */
function _getComponentElement($customElem = $(document.documentElement)){

    if (!_.isElement($customElem.get(0))){
        CONSOLE.prop.throw(BxImg, '$customElem', 'type');
    }

    const opts = _createComponentOptions.call(this, $customElem, OPTS);

    const $container = _createComponentContainer.call(this, opts);

    // native event 바인드
    UTIL.addAllEventListenerWithProperty($container, opts.events);

    return $container;
}

/**
 * 각 `custom` 엘리먼트에 정의된 attr 를 opt 객체로 반환한다.
 *
 * @param {object} [targetObject=null]
 * @param {object} [defaultOpts={}]
 *
 * @returns {object} 생성된 opt 객체
 *
 * @private
 * @memberOf BxImg
 */
function _createComponentOptions(targetObject = null, defaultOpts = {}){

    if (_.isNull(targetObject)){
        CONSOLE.prop.throw(BxImg, 'targetObject', 'type');
    }

    if (!_.isFunction(targetObject.get) && !_.isPlainObject(targetObject)){
        CONSOLE.prop.throw(BxImg, 'targetObject', 'type');
    }

    if (!_.isPlainObject(defaultOpts)){
        CONSOLE.prop.throw(BxImg, 'defaultOpts', 'type');
    }

    let opts = UTIL.createComponentOptions(targetObject, defaultOpts, ATTRNAMES, function(k, v){

        // 최초 설정시 유효성 검사
        if (k === 'url' || k === 'errUrl' || k === 'caption' || k === 'desc' || k === 'btnText' || k === 'data-title'){

            if (!_.isString(v)){
                CONSOLE.prop.throw(BxImg, k, 'type');
            }
        }

        if (k === 'shape' && _.isUndefined(SHAPE[v])){
            CONSOLE.prop.throw(BxImg, k, 'type');
        }

        if (k === 'size' && _.isUndefined(SIZE[v])){
            CONSOLE.prop.throw(BxImg, k, 'type');
        }

        if (k === 'captionAlign' && _.isUndefined(ALIGN[v])){
            CONSOLE.prop.throw(BxImg, k, 'type');
        }

        if (k === 'overlayStyle' && _.isUndefined(OVERLAY_STYLE[v])){
            CONSOLE.prop.throw(BxImg, k, 'type');
        }

        if (k === 'frameType' && _.isUndefined(FRAME_TYPE[v])){
            CONSOLE.prop.throw(BxImg, k, 'type');
        }

        if (k === 'data-width' || k === 'data-height'){

            v = parseInt(v, 10);

            if (isNaN(v)){
                CONSOLE.prop.throw(BxImg, k, 'type');
            }
        }

        return v;

    }, function(k, v){

        return v;
    });

    return opts;
}

/**
 * image 컴포넌트를 생성한다
 *
 * @param {object} opts={} - 옵션 객체
 * @returns {object} 생성된 image component container
 *
 * @private
 * @memberOf BxImg
 */
function _createComponentContainer(opts = {}){

    let html = [];
    let imgAttr = UTIL.objectToStringAttr(opts.attr);

    let originSrc = opts.url;
    let size = _.isUndefined(SIZE[opts.size]) ? '' : SIZE[opts.size].class;
    let frameType = FRAME_TYPE[opts.frameType] || FRAME_TYPE.default;
    let shape = SHAPE[opts.shape] || opts.shape;
    let captionAlign = ALIGN[opts.captionAlign] || opts.captionAlign;
    let overlayStyle = OVERLAY_STYLE[opts.overlayStyle] || '';

    let fileName = FILE.getFileNameInfo(opts.url).name;
    let alt = opts.attr.alt || fileName;
    let title = opts['data-title'] || fileName;

    let desc = opts.desc;
    let caption = opts.caption;
    let btnText = opts.btnText;

    let width = opts['data-width'] || '';
    let height = opts['data-height'] || '';
    let widthStyle = width === '' ? width : `width:${width}px;`;
    let heightStyle = height === '' ? height : `height:${height}px;`;

    // overlayStyle 이 half 일 때 만 captionAlign 을 적용시킨다
    if (overlayStyle === '') captionAlign = ALIGN.center;

    // 사용자가 width 나 height 를 넣은 경우 size 를 없앤다
    if (width !== '' || height !== '') size = '';

    html.push(`<div class="${CLASS_NAME.wrap}">`);
    html.push(`<figure title="${title}" class="${shape} ${size} ${frameType} ${overlayStyle} ${captionAlign}" style="${widthStyle} ${heightStyle}">`);
    html.push(`<img ${imgAttr} alt="${alt}" title="${title}" />`);
    html.push(`<div class="dim-area"></div>`);
    html.push('<figcaption>');
    html.push(`<p>${caption}</p>`);
    html.push('</figcaption>');
    html.push(`<div class="${CLASS_NAME.btn}">`);

    if (btnText !== '') html.push(`<button type="button">${btnText}</button>`);

    html.push('</div>');
    html.push('</figure>');
    html.push(`<div class="${CLASS_NAME.desc}">`);
    html.push(`<p>${desc}</p>`);
    html.push('</div>');
    html.push('</div>');

    const $wrap = $(html.join(''));
    const $image = $wrap.find('img');
    const $button = $wrap.find('button');
    const $dimArea = $wrap.find('.dim-area');

    // 최초에 이미지는 hide처리 (ie의 아이콘 때문에)
    $image.hide();

    // 최초 컴포넌트 사이즈 설정
    _setComponentSize($dimArea, {size, width, height});

    // 컴포넌트 프로퍼티 설정
    _setElementProperties.call(this, opts, $wrap.get(0));

    // paper 설정
    // _clickOpenPaper.call(this, $image);

    // lazyload 설정
    _setLazyLoad.call(this, $image, originSrc);

    // button 설정
    $button.on('click', e => $wrap.prop('bxbtnClick').call($wrap.get(0), e));

    // dim 활성화
    _showDim.call(this, $dimArea, $image);

    return $wrap;
}


/**
 * image 엘리먼트의 프로퍼티를 설정한다.
 *
 * @param {object} [opts={}] - 옵션 객체
 * @param {object} [elem=null] - 프로퍼티가 추가될 엘리먼트
 *
 * @returns {object} 생성된 인스턴스
 *
 * @private
 * @memberOf BxImg
 */
function _setElementProperties(opts = {}, elem = null){

    if (!_.isPlainObject(opts)){
        CONSOLE.prop.throw(BxImg, 'opts', 'type');
    }

    if (!_.isElement(elem)){
        CONSOLE.prop.throw(BxImg, 'elem', 'type');
    }

    const bxPtn = /^bx/;

    _.map(opts, (v, k) => {

        // attr 속성은 무시한다.
        if (k === 'attr') return;
        // events 속성은 무시한다.
        if (k === 'events') return;

        // 읽기 전용 속성
        if (READONLY_PROPERTY[k]){
            UTIL.setReadOnlyProperty(elem, k, v);
        }
        else{

            if (k.match(bxPtn)){

                let _k = k.replace('-', '');
                delete opts[_k];

                k = _k;
            }

            let _k = UTIL.convertInternalPropertyName(k);

            elem[_k] = v;

            UTIL.setPropertyWithDescriptor(elem, k, {
                configurable: true,
                enumerable: true,
                get: () => {
                    return elem[_k];
                },
                set: v => {

                    if (k === 'url' || k === 'desc' || k === 'caption' || k === 'btnText' || k === 'data-title'){

                        if (!_.isString(v)){
                            CONSOLE.prop.throw(BxImg, k, 'type');
                        }
                    }

                    if (k === 'captionAlign' && _.isUndefined(ALIGN[v])){
                        CONSOLE.prop.throw(BxImg, k, 'type');
                    }

                    elem[_k] = v;

                    if (k === 'url'){
                        // $(elem).attr('src', v);
                        _update.call(this, $(elem).parents(`.${CLASS_NAME.wrap}`));
                    }

                    if (k === 'desc' || k === 'caption' || k === 'btnText' || k === 'data-title'){
                        _changeText(elem, k, v);
                    }

                    if (k === 'captionAlign'){
                        _changeTextAlign(elem, v);
                    }

                    if (k === 'data-width' || k === 'data-height'){
                        _changeComponentSize(elem, k, v);
                    }
                }
            }, v);
        }
    });

    // API 에 대한, 프로퍼티 할당
    // _.map(APIS, (v, k) => {
    //     UTIL.setReadOnlyProperty(elem, k, v);
    // });
}

/**
 * lazyload를 설정한다
 *
 * @param {object} $image - image container
 * @param {string} originImage - 사용자가 설정한 보여줄 이미지
 *
 * @private
 * @memberOf BxImg
 */
function _setLazyLoad($image = {}, originImage = ''){

    $image.one('appear', () => {

        let $figureWrap = $image.parent();
        let $dimContainer = $figureWrap.children('.dim-area');
        let $dim = $image.prop('$dim');

        let frameType = $image.prop('frameType');
        let size = $image.prop('size');
        let width = $image.prop('data-width');
        let height = $image.prop('data-height');
        let title = $image.prop('data-title');

        $image
            .on('load', e => {

                // dim container hide
                $dimContainer.hide();
                // dim 해제
                $dim.hide();

                let sizeClass = '';

                // 이미지 사이즈가 있고 width, height값이 없는 경우에만 size class 추가
                if (!_.isUndefined(SIZE[size]) && _.isNull(width) && _.isNull(height)){
                    sizeClass = SIZE[size].class;
                }

                // 이미지의 사이즈는 설정되있으니 없는 경우에 재등록 (에러 이미지에서 정상 이미지로 변경되었을 때)
                if (!$figureWrap.hasClass(sizeClass)) $figureWrap.addClass(sizeClass);

                $image.prop('isLoaded', true).show();

            })
            .on('error', e => {

                let errorImg = $image.prop('errUrl');

                if (errorImg === '') errorImg = ERROR_IMG;

                let fileName = FILE.getFileNameInfo(errorImg).name;
                title = title || fileName;

                // frameType이 horizon이나 vertical일 경우 wrapper size의 auto값이 없기 때문에 강제 설정
                if (frameType === 'horizon' || frameType === 'vertical'){

                    _setComponentSize($figureWrap, {size, width, height});

                    if (size && $figureWrap.hasClass(SIZE[size].class)){
                        $figureWrap.removeClass(SIZE[size].class);
                    }
                }

                // 에러 이미지 background로 설정
                $dimContainer.show().addClass('no-img');

                // 기본 이미지를 상대 경로로 설정했을 때 사이트의 상대경로로 보는 이슈때문에 분리
                if (errorImg !== ERROR_IMG) $dimContainer.css("background-image", `url(${errorImg})`);

                $figureWrap.attr('title', title);

                $dim.hide();
                $image.hide();
            })
            .attr('src', originImage);
    });
}

/**
 * 이미지 상태를 변경한다
 *
 * @param {object} $container - image container
 *
 * @private
 * @memberOf BxImg
 */
function _update($container = {}){

    let $image = $container.find('img');
    let $dim = $container.find('.dim-area');

    // 이미 로딩된 이미지는 진행하지 않는다
    if ($image.prop('isLoaded')) return this;

    // 이미지가 viewport 내부에 들어왔을 때 이미지 로딩을 시작한다
    if (UTIL.isInViewport($dim)){
        $image.trigger('appear');
    }
}

/**
 * element 컴포넌트 크기를 설정한다
 *
 * @param {object} $elem - element
 * @param {object} options - 사이즈 설정 오브젝트
 *
 * @private
 * @memberOf BxImg
 */

function _setComponentSize($elem = null, options = {}){

    let defaultValue = SIZE['medium'].value;
    let width = options.width === '' ? defaultValue : options.width;
    let height = options.height === '' ? defaultValue : options.height;

    if (options.size !== ''){
        width = height = defaultValue;
    }

    $elem.css({width, height});
}

