/**
 * 이미지 컴포넌트에 이벤트를 등록한다
 *
 * @param {object} $container - image container
 *
 * @private
 * @memberOf BxImg
 */
function _addDocumentElementEventListener($container = {}){

    // window resize event 등록
    _addResizeListenerAtWindow.call(this, $container);

    // window scroll event 등록
    _addScrollListenerAtWindow.call(this, $container);
}

/**
 * 윈도우 resize 이벤트를 등록한다
 *
 * @param $container - image container
 *
 * @private
 * @memberOf BxImg
 */
function _addResizeListenerAtWindow($container = {}){

    let $window = $(window);

    $window.on('resize', e => {
        _update.call(this, $container);
    });
}

/**
 * 윈도우 scroll 이벤트를 등록한다
 *
 * @param $container - image container
 *
 * @private
 * @memberOf BxImg
 */
function _addScrollListenerAtWindow($container = {}){

    let $window = $(window);

    $window.on('scroll', e => {

        let $image = $container.find('img');
        let timeoutObj = $image.prop('timeoutObj');

        if (!_.isUndefined(timeoutObj)) clearTimeout(timeoutObj);

        timeoutObj = setTimeout(()=>{
            _update.call(this, $container);
        }, UPDATE_DURATION);

        $image.prop('timeoutObj', timeoutObj);
    });
}

/**
 * 컴포넌트 내부 텍스트를 변경한다
 *
 * @param {object} elem - image element
 * @param {string} k - property key
 * @param {string} v - property value
 *
 * @private
 * @memberOf BxImg
 */
function _changeText(elem = null, k = '', v = ''){

    let $container = $(elem).parents(`.${CLASS_NAME.wrap}`);

    switch (k){

        case 'desc': {
            $container.find(`.${CLASS_NAME.desc} p`).html(v);
            break;
        }
        case 'caption': {
            $container.find('figcaption p').text(v);
            break;
        }
        case 'btnText': {
            $container.find('button').text(v);
            break;
        }
        case 'data-title': {
            $container.find('figure').attr('title', v);
            $container.find('img').attr('title', v);
            break;
        }
    }
}

/**
 * 캡션 및 버튼의 정렬을 변경한다
 *
 * @param {object} elem - image element
 * @param {string} v - property value
 *
 * @private
 * @memberOf BxImg
 */
function _changeTextAlign(elem = null, v = ''){

    let $container = $(elem).parent();

    // overlayStyle이 half type인 경우에만 align 적용
    if ($container.hasClass(OVERLAY_STYLE.half)){

        if ($container.hasClass(ALIGN.left)){
            $container.removeClass(ALIGN.left);
        }
        else if ($container.hasClass(ALIGN.right)){
            $container.removeClass(ALIGN.right);
        }

        $container.addClass(ALIGN[v]);
    }
}

/**
 * 컴포넌트 사이즈를 변경한다
 *
 * @param {object} elem - image element
 * @param {string} k - property key
 * @param {object} v - property value
 *
 * @private
 * @memberOf BxImg
 */
function _changeComponentSize(elem = null, k = '', v = null){

    let $container = $(elem).parent();

    k = k.split('-')[1];

    $container.css(k, `${v}px`);
}

/**
 * lazyload 전에 실행 될 dim을 그린다
 *
 * @param {object} elem - image element
 *
 * @private
 * @memberOf BxImg
 */
function _showDim($elem = null, $image = {}){

    let $dim = $elem.bxDim(DIM_STYLE);

    $dim.show();

    $image.prop('$dim', $dim);
}

module.exports = BxImg;
